        row3_paid = ws.cell(row=3, column=paid_col).value
        row3_adj = ws.cell(row=3, column=adj_col).value
        errors = []
        if str(row3_status).strip() != 'Written Off':
            errors.append(f'Claim_Status is "{row3_status}", expected "Written Off"')
        try:
            if abs(float(str(row3_billed).replace(',','')) - 285) > 2.85:
                errors.append(f'Billed_Amount is "{row3_billed}", expected 285')
        except:
            errors.append(f'Billed_Amount "{row3_billed}" is not numeric')
        try:
            if abs(float(str(row3_paid).replace(',','')) - 285) > 2.85:
                errors.append(f'Paid_Amount is "{row3_paid}", expected 285')
        except:
            errors.append(f'Paid_Amount "{row3_paid}" is not numeric')
        try:
            if abs(float(str(row3_adj).replace(',','')) - 0) > 2.85:
                errors.append(f'Adjustment_Amount is "{row3_adj}", expected 0')
        except:
            errors.append(f'Adjustment_Amount "{row3_adj}" is not numeric')
        if errors:
            return {'pass': False, 'score': 0.0, 'feedback': 'Row 3 issues: ' + '; '.join(errors)}
        return {'pass': True, 'score': 1.0, 'feedback': f'Row 3 has Claim_Status="Written Off", Billed_Amount={row3_billed}, Paid_Amount={row3_paid}, Adjustment_Amount={row3_adj} as expected'}
    except Exception as e:
        return {'pass': False, 'score': 0.0, 'feedback': f'Error reading PBC_Claim_Register.xlsx: {str(e)}'}

