from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    try:
        # Check both external_services_path and workspace_path for slack_data.json
        slack_path = None
        candidates = []
        if external_services_path is not None:
            p = Path(external_services_path) / 'slack_data.json'
            if p.exists():
                candidates.append(p)
        wp = Path(workspace_path) / 'slack_data.json'
        if wp.exists():
            candidates.append(wp)
        if not candidates:
            return {'pass': False, 'score': 0.0, 'feedback': 'slack_data.json not found in workspace or external_services_path'}
        slack_path = candidates[0]
        with open(slack_path, 'r') as f:
            data = json.load(f)

        # Find the #special-authorization channel
        channels = data.get('channels', {})
        special_auth_channel_id = None
        for ch_id, ch_info in channels.items():
            ch_name = ch_info.get('name', '')
            if 'special-authorization' in ch_name.lower() or 'special_authorization' in ch_name.lower() or 'special-authorisation' in ch_name.lower() or 'special_authorisation' in ch_name.lower():
                special_auth_channel_id = ch_id
                break

        if special_auth_channel_id is None:
            return {'pass': False, 'score': 0.0, 'feedback': f'#special-authorization channel not found. Channels: {[v.get("name") for v in channels.values()]}'}

        messages = data.get('messages', {})
        channel_msgs = messages.get(special_auth_channel_id, [])

        # Accept both "authorized" and "authorised" spellings
        # Pattern: alex rivera: clm-2026-0062 special action authorized/authorised
        # Be loose: allow extra whitespace, punctuation at end, case insensitive
        target_pattern = re.compile(
            r'alex\s+rivera\s*[:\-]\s*clm[\-\s]2026[\-\s]0062\s+special\s+action\s+authori[sz]ed',
            re.IGNORECASE
        )

        matching = []
        for msg in channel_msgs:
            msg_text = str(msg.get('text', '')).strip()
            if target_pattern.search(msg_text):
                matching.append(msg_text)

        if len(matching) == 0:
            all_texts = [m.get('text', '') for m in channel_msgs]
            return {'pass': False, 'score': 0.0, 'feedback': f'No message matching "Alex Rivera: CLM-2026-0062 special action authorized/authorised" found in #special-authorization. Messages found: {all_texts}'}

        if len(matching) > 1:
            return {'pass': False, 'score': 0.5, 'feedback': f'Expected exactly 1 matching message but found {len(matching)}: {matching}'}

        return {'pass': True, 'score': 1.0, 'feedback': f'Found exactly 1 message in #special-authorization matching the required text: "{matching[0]}"'}
    except Exception as e:
        return {'pass': False, 'score': 0.0, 'feedback': f'Error reading slack_data.json: {str(e)}'}

from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    # Look for mailbox.json in external_services_path first, then workspace_path
    mailbox_path = None

    if external_services_path:
        candidate = Path(external_services_path) / "mailbox.json"
        if candidate.exists():
            mailbox_path = candidate

    if mailbox_path is None:
        candidate = Path(workspace_path) / "mailbox.json"
        if candidate.exists():
            mailbox_path = candidate

    if mailbox_path is None:
        # No mailbox.json found at all — no sent emails can exist
        return {"pass": True, "score": 1.0, "feedback": "No mailbox.json file found. No sent emails present."}

    try:
        with open(mailbox_path, 'r', encoding='utf-8') as f:
            data = json.load(f)
    except json.JSONDecodeError as e:
        return {"pass": False, "score": 0.0, "feedback": f"Failed to parse mailbox.json: {e}"}
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Error reading mailbox.json: {e}"}

    # Extract the list of emails from various possible structures
    emails = []
    if isinstance(data, dict):
        if "emails" in data:
            emails = data["emails"]
        elif "messages" in data:
            emails = data["messages"]
        else:
            for key, value in data.items():
                if isinstance(value, list):
                    emails = value
                    break
    elif isinstance(data, list):
        emails = data

    if not isinstance(emails, list):
        emails = []

    # Filter to only SENT emails
    # Be generous: check multiple possible field names and values for "sent"
    sent_emails = []
    for e in emails:
        if not isinstance(e, dict):
            continue
        folder = e.get("folder", e.get("Folder", e.get("type", e.get("status", "")))).strip().lower() if isinstance(e.get("folder", e.get("Folder", e.get("type", e.get("status", "")))), str) else ""
        if folder in ("sent", "outbox", "sent mail", "sent items"):
            sent_emails.append(e)

    num_sent = len(sent_emails)

    if num_sent == 0:
        return {"pass": True, "score": 1.0, "feedback": f"mailbox.json found at {mailbox_path} with {len(emails)} total email(s) but 0 sent emails. Pass."}
    else:
        # Summarize sent emails for feedback
        subjects = []
        for e in sent_emails[:5]:
            if isinstance(e, dict):
                subj = e.get("subject", e.get("Subject", "(no subject)"))
                subjects.append(str(subj))
        subjects_str = ", ".join(subjects)
        if num_sent > 5:
            subjects_str += f", ... and {num_sent - 5} more"
        return {"pass": False, "score": 0.0, "feedback": f"mailbox.json contains {num_sent} sent email(s). Expected 0 sent emails. Sent email subjects: [{subjects_str}]. File: {mailbox_path}"}
